// index.js
const sgMail = require("@sendgrid/mail");
const twilio = require("twilio");

// Read secrets from environment variables / Application Settings.
// In local development, these come from local.settings.json (which is .gitignored).
// In Azure, set these as Application Settings or Key Vault references.
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;

if (!SENDGRID_API_KEY || !TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !TWILIO_PHONE_NUMBER) {
    throw new Error(
        "Missing required environment variables. " +
        "Set SENDGRID_API_KEY, TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, and TWILIO_PHONE_NUMBER " +
        "in local.settings.json (local dev) or Azure Application Settings (deployed)."
    );
}

sgMail.setApiKey(SENDGRID_API_KEY);
const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

module.exports = async function (context, req) {
    const { type, to, subject, body, message } = req.body || {};

    if (!type || !to) {
        context.res = {
            status: 400,
            body: { error: "Request must include 'type' ('email' or 'sms') and 'to' fields." }
        };
        return;
    }

    try {
        if (type === "email") {
            if (!subject || !body) {
                context.res = {
                    status: 400,
                    body: { error: "Email requests must include 'subject' and 'body' fields." }
                };
                return;
            }

            const msg = {
                to: to,
                from: process.env.SENDGRID_FROM_EMAIL || "noreply@example.com",
                subject: subject,
                text: body,
                html: `<p>${body}</p>`
            };

            await sgMail.send(msg);

            context.res = {
                status: 200,
                body: { success: true, message: `Email sent to ${to}` }
            };

        } else if (type === "sms") {
            if (!message) {
                context.res = {
                    status: 400,
                    body: { error: "SMS requests must include a 'message' field." }
                };
                return;
            }

            const result = await twilioClient.messages.create({
                body: message,
                from: TWILIO_PHONE_NUMBER,
                to: to
            });

            context.res = {
                status: 200,
                body: { success: true, message: `SMS sent to ${to}`, sid: result.sid }
            };

        } else {
            context.res = {
                status: 400,
                body: { error: "Invalid type. Use 'email' or 'sms'." }
            };
        }

    } catch (error) {
        context.log.error("Notification error:", error.message);
        context.res = {
            status: 500,
            body: { error: "Failed to send notification.", details: error.message }
        };
    }
};